#include <bits/stdc++.h>
using namespace std;
const int maxn=1e6+5;
int n,flag[maxn],sum,ans,siz[maxn];
long long dp[maxn];
vector<int> g[maxn];
void dfs(int u,int fa,int s) {
	siz[u]=1;
	dp[1]+=s;
	for(auto v:g[u]) {
		if(v==fa) {
			continue;
		}
		dp[v]=dp[u]+n-2*siz[v];
		dfs(v,u,s+1);
		siz[u]+=siz[v];
	}
}
void dfs1(int u,int fa) {
	for(auto v:g[u]) {
		if(v==fa) {
			continue;
		}
		dp[v]=dp[u]+n-2*siz[v];
		dfs1(v,u);
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	if(n==1){
		cout<<n;
		return 0;
	}
	for(int i=1; i<n; i++) {
		int u,v;
		cin>>u>>v;
		g[u].emplace_back(v);
		g[v].emplace_back(u);
	}
	dfs(1,0,0);
	dfs1(1,0);
	for(int i=1; i<=n; i++) {
		if(dp[i]>dp[ans]) {
			ans=i;
		}
	}
	cout<<ans;
	return 0;
}
